94	/// When `--quiet` is set, the global log filter is temporarily clamped
95	/// to `Warn` for the duration of the call and restored on return, so
96	/// `info!` calls throughout sync (plus any subprocess-stderr routed
97	/// through `common::run`) go dark. Errors still surface at `Warn` /
98	/// `Error` so script callers don't lose diagnostics.
99	pub fn sync(args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
100	    let repos = resolve_repos(&args.repos);
101	    if args.quiet {
102	        let prev = log::max_level();
103	        log::set_max_level(LevelFilter::Warn);
104	        let result = sync_repos(&repos, args);
105	        log::set_max_level(prev);
106	        result
107	    } else {
108	        sync_repos(&repos, args)
109	    }
110	}
