112	/// Sync the given repos against their remotes.
113	///
114	/// Orchestrates the full flow: pre-flight clean-check on every repo,
115	/// snapshot each repo's current op id, then hand off to `run_plan` for
116	/// fetch + classify + (optional) act. On any error, revert every repo
117	/// to its snapshot op via `jj op restore` so the caller sees an atomic
118	/// "either it all went through or nothing changed" outcome.
119	///
120	/// Paths may be relative (resolved against the process cwd) or
121	/// absolute. Tests use absolute tempdir paths to avoid cwd dependence
122	/// under parallel `cargo test`.
123	pub fn sync_repos(repos: &[PathBuf], args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
124	    debug!(
125	        "sync: enter (no_dry_run={}, bookmark={}, remote={})",
126	        args.no_dry_run, args.bookmark, args.remote
127	    );
128	
129	    let mut snapshots: Vec<(PathBuf, String)> = Vec::new();
130	    for repo in repos {
131	        let op_id = current_op_id(repo)?;
132	        debug!("{}: op snapshot = {op_id}", repo.display());
133	        snapshots.push((repo.clone(), op_id));
134	    }
135	
136	    let result = run_plan(&snapshots, args);
