271	    let matches = cli_with_banner().get_matches();
272	    let cli = match Cli::from_arg_matches(&matches) {
273	        Ok(cli) => cli,
274	        Err(e) => {
275	            e.exit();
276	        }
277	    };
278	
279	    let log_path = cli.log.as_ref().map(|p| p.to_string_lossy().to_string());
280	    logging::CliLogger::init(cli.verbose, log_path.as_deref());
281	
282	    // The detached `finalize --exec` re-entry is the bot's
283	    // session-end child; it shouldn't print the banner (extra
284	    // chatter in its log) or surface user-facing failure markers
285	    // (those are meant for the user's next interactive run).
286	    let is_detached_exec = matches!(
287	        cli.command,
288	        Commands::Finalize(ref f) if f.exec
289	    );
